sql:
SELECT population_size 
FROM countries 
WHERE country_name = 'YourCountryName';

SELECT team_name
FROM research_teams
WHERE team_id = 1;

external_knowledge:
- "The land of the Afghans" refers to Afghanistan;
- "Early part of the last century" refers to the years between 1900 and 1950;
- "Population figures" refer to the total population counts recorded in the database.

sql:
SELECT COUNT(DISTINCT country_name) AS count_of_countries, iso3
FROM countries
WHERE geographic_region = 'Asia';

SELECT MIN(country_name) 
FROM countries 
WHERE country_id BETWEEN 10 AND 50 AND capital = country_name;
